import { RefObject } from 'react';
import type { CalendarTimeframeState, CalendarTimeframeStoreActions } from './calendar.types.js';
import type { DateTimeInputRef } from '../../../forms/date-time-range-picker/types.js';
import { FormControlWithOverlayRef } from '../../../forms/shared-types.js';
import type { TimeValue } from '../../types/time.js';
import type { TimeErrorKey } from '../shared.types.js';
/**
 * State slice for the DateTimePicker component.
 * Extends CalendarTimeframeState to inherit calendar state while adding
 * picker-specific state for managing single date-time value input.
 * @internal
 */
export type DateTimePickerValueStates = CalendarTimeframeState & {
    /** The current date-time value being edited in the picker. */
    dateTimePickerValue: TimeValue | null;
    /** Ref to the DateTimeInput used for robust post-calendar focus handling. */
    dateTimeInputRef: RefObject<DateTimeInputRef>;
    /** Ref to the DateTimePicker for imperative access (open/close overlay, focus, validation). */
    dateTimePickerRef: RefObject<FormControlWithOverlayRef<HTMLSpanElement>>;
    /** Current validation error state specific to the picker (e.g., out of bounds). */
    dateTimePickerError?: TimeErrorKey;
    /** ISO Format depending on the current locale and precision. */
    formatString?: string;
};
/**
 * Actions slice for the DateTimePicker component.
 * Extends CalendarTimeframeStoreActions to inherit calendar actions while adding
 * picker-specific actions for updating the single date-time value.
 * @internal
 */
export type DateTimePickerValueStoreActions = CalendarTimeframeStoreActions & {
    /**
     * Updates the picker value when user edits the input. Validates and syncs with calendar.
     * @param value - The new date-time value as ISO string or null to clear.
     */
    setDateTimePickerValue: (value: TimeValue | string | null) => void;
};
/**
 * Combined DateTimePicker store type (state + actions).
 * Use this when consuming the full DateTimePicker store.
 * @internal
 */
export type DateTimePickerValueStore = DateTimePickerValueStates & DateTimePickerValueStoreActions;
